import axios from "axios"
import { JsonToFormData } from "./json-to-form-data"
import APIEndPoints from "../../consts/api-end-points"
import { toast } from "react-toastify"
import ClearUserData from "./clear-user-data"

export const refreshToken = async () => {
  let response: any
  const url = APIEndPoints.refresh
  const data = { refresh: APIEndPoints.refreshToken }
  await axios
    .post(url, JsonToFormData(data))
    .then((res) => {
      response = res
    })
    .catch(function (e) {
      response = e.response ?? {}
      console.log(e.response)
    })
  switch (response.status) {
    case 200:
      APIEndPoints.accessToken = response.data.access
      break
    case 400:
      toast.error(JSON.stringify(response.data.message ?? {}), {
        position: "top-center"
      })
      break
    case 401:
      toast.error("user isn't authorized", {
        position: "top-center"
      })
      ClearUserData()
      // TODO: redirect to login page
      break
    case 500:
      toast.error(JSON.stringify(response.data.message ?? {}), {
        position: "top-center"
      })
      break
    case undefined:
      toast.error("Cannot connect to server", {
        position: "top-center"
      })
      break
    default:
      break
  }
  return response
}

export const verifyToken = async () => {
  let response: any
  const url = APIEndPoints.verify
  const data = { token: APIEndPoints.refreshToken }
  await axios
    .post(url, JsonToFormData(data))
    .then((res) => {
      response = res
    })
    .catch(function (e) {
      response = e.response ?? {}
      console.log(e.response)
    })
  switch (response.status) {
    case 200:
      await refreshToken()
      break
    case 400:
      toast.error(JSON.stringify(response.data.message ?? {}), {
        position: "top-center"
      })
      break
    case 401:
      toast.error("user isn't authorized", {
        position: "top-center"
      })
      ClearUserData()
      // Logout
      break
    case 500:
      toast.error(JSON.stringify(response.data.message ?? {}), {
        position: "top-center"
      })
      break
    case undefined:
      toast.error("Cannot connect to server", {
        position: "top-center"
      })
      break
    default:
      break
  }
  return response
}
